+/// Errors that can occur during LLM operations.
+public enum LLMError: Error {
+    case modelLoadFailed
+    case contextCreationFailed
+    case tokenizationFailed
+    case decodingFailed
+    case inputTooLong
+    case decodeFailed
+    case embeddingsFailed
