+            postprocess(rawOutput)
+            return output
+        } catch {
+            print("JSON Decoding failed:")
+            print("Raw output: '\(rawOutput)'")
+            print("JSON data: '\(String(data: jsonData, encoding: .utf8) ?? "nil")'")
+            print("Error: \(error)")
+            print("Schema: \(T.jsonSchema)")
+            throw StructuredOutputError.decodingFailed
